from agent import *from models.products import *import reXWORD = ['Análise', 'SAPO', 'TEK', 'Primeiras', 'impressões ', '- Fotos', 'TeK', 'fotos', 'tablet', 'Teclado', 'tek', 'analise', 'Fotografias', 'captadas', 'All in one', 'Impressões', 'do', 'Tek', 'Um', 'com o']CONCWORD1 = ['Somando todas as partes,', 'De um modo geral,', 'Em jeito de conclusão,', 'Forte concorrência', 'E a conclusão?', 'Por fim,', 'Em conclusão…']CONCWORD2 = ['Considerações finais', 'Veredito final sobre o ', 'Veredito final']GIF = 'http://imgs.sapo.pt/gfx/'def run(context, session):    session.browser.agent = "Mozilla/5.0 (Macintosh; Intel Mac OS X 10.9; rv:37.0) Gecko/20100101 Firefox/37.0"    session.queue(Request('https://tek.sapo.pt/analises'), process_revlist, dict())def process_revlist(data, context, session):    for rev in data.xpath('//li//h3[contains(@class, "no-margin-bottom")]'):        url = rev.xpath(".//@href").string()        session.queue(Request(url), process_review, dict(context, url=url))    next_url = data.xpath("//li[@class='next']//@href").string()    if next_url:        session.queue(Request(next_url), process_revlist, dict(context))def process_review(data, context, session):    product = Product()    names = data.xpath("""//ul/li/a/picture[contains(@data-caption, "h6 class='pswp-caption-title'")]/parent::a[@data-index="1"]/@title""")    name = ''    if len(names) == 1:        name = names.string()    elif len(names) == 2 or len(names) == 5:        name = names[0].string()        if not name:            name = names[1].string()    elif len(names) == 3 or len(names) == 4:        name = names[1].string()    if not name:        name = data.xpath('//meta[@itemprop="headline"]/@content').string()        if name:            name = name.replace('Análise TeK: ', '')    for word in XWORD:        if word in name:            name = name.replace(word, '')    if name:        product.name = name.strip(' |-:')    product.url = context["url"]    product.ssid = product.url.split('/')[-1]    product.category = 'Tecnologia'    review = Review()    review.type = 'pro'    review.title = data.xpath("//h1[@id='article-title']//text()").string(multiple=True)    review.url = product.url    review.ssid = product.ssid    date = data.xpath('//meta[@itemprop="datePublished"]/@content').string()    if date:        review.date = date.split('T')[0]    author = data.xpath("//a[contains(@class, 'author has-avatar')]").first()    if not author:        author = data.xpath('//div[@class="content"]//p//a[contains(@href, "mailto")]').first()    if author:        url = author.xpath("@href").string()        name = data.xpath("//span[contains(@class, 'name')]//text()").string(multiple=True)        if not name:            name = author.xpath('text()').string()        if name and url and "mailto" in url:            url = url.replace('mailto:', '').strip(' +')            review.authors.append(Person(name=name, ssid=name, email=url))        elif url and name:            review.authors.append(Person(name=name, ssid=name, url=url))        elif name:            review.authors.append(Person(name=name, ssid=name))    summary = data.xpath("//div[contains(@class, 'article-excerpt')]//text()").string(multiple=True)    if summary:        review.add_property(type='summary', value=summary)    full_text = data.xpath('//div[@class="content"]//p[not(.//a[contains(@href, "mailto")])]//text()').string(multiple=True)    conclusion = ''    if full_text:        full_text = re.sub(r"\[.*?\]", '', full_text)        for word in CONCWORD1:            if word in full_text:                conclusion = word + full_text.split(word)[-1]                review.add_property(type='conclusion', value=conclusion)                break        for word in CONCWORD2:            if word in full_text:                conclusion = full_text.split(word)[-1]                review.add_property(type='conclusion', value=conclusion)                break    pros = data.xpath("//div[@class='content']//p//*[text()[contains(.,'Pontos fortes')]]/parent::p//text()").string(multiple=True)    if pros:        review.add_property(type='pros', value=pros)    cons = data.xpath("//div[@class='content']//p//*[text()[contains(.,'Pontos fracos')]]/parent::p//text()").string(multiple=True)    if cons:        review.add_property(type='cons', value=cons)    excerpt = data.xpath('''//div[@class="content"]//p[not(.//a[contains(@href, "mailto")])][not(contains(., "Escrito ao abrigo do novo Acordo Ortográfico"))][not(contains(., 'Ficam as especificações "oficiais":'))]//text()[not(contains(., "Veredito final"))]''').string(multiple=True)    if excerpt:        while GIF in excerpt:            flag = excerpt.find(GIF)            excerpt = excerpt.replace(excerpt[flag:flag+34], '')        excerpt = re.sub(r"\[.*?\]", '', excerpt)        if conclusion:            excerpt = excerpt.split(conclusion)[0]        review.add_property(type='excerpt', value=excerpt)        product.reviews.append(review)        session.emit(product)